import type { JSX } from 'react';
import React from 'react';

const getValueText = (value: unknown): string => {
	if (value === null || value === undefined) {
		return '';
	}

	if (typeof value === 'object') {
		const option = value as Record<string, unknown>;
		const resolvedValue = option.value ?? option.label ?? option.name ?? value;
		return resolvedValue === null || resolvedValue === undefined ? '' : String(resolvedValue);
	}

	return String(value);
};

// TODO: key
export const createChilds = <T,>(values: T[]): React.JSX.Element[] => {
	const lastIndex = values.length - 1;
	return values.map((val, i) => {
		const text = getValueText(val);
		return <span key={`${i}-${text}`}>{i === lastIndex ? text : `${text}, `}</span>;
	});
};

export const throttle = <T extends (...args: any[]) => any>(cb: T, delay = 100): T => {
	let shouldWait = false;
	let waitingArgs: Parameters<T> | null = null; // Use Parameters<T> type for waitingArgs

	const timeoutFunc = (): void => {
		if (waitingArgs === null) {
			shouldWait = false;
		} else {
			cb(...waitingArgs); // Spread works correctly with Parameters<T> as an array
			waitingArgs = null;
			setTimeout(timeoutFunc, delay);
		}
	};

	return ((...args: Parameters<T>) => {
		if (shouldWait) {
			waitingArgs = args; // Store args as Parameters<T>
			return;
		}

		cb(...args); // Spread works correctly here as well
		shouldWait = true;
		setTimeout(timeoutFunc, delay);
	}) as T;
};

interface CountOfOverflowNodes {
	parentRight: number;
	nodes: NodeListOf<ChildNode>;
}

export const countOfOverflowNodes = ({ parentRight, nodes }: CountOfOverflowNodes): number => {
	let cnt = 0;
	let isFirstNodeOverflowed = false;
	const entries = Object.entries(nodes);

	for (const [key, childNode] of entries) {
		const child = childNode as HTMLElement;
		const { left, right } = child.getBoundingClientRect();
		const isOverflowed = right - (right - left) / 10 > parentRight;
		if (isOverflowed) {
			if (key === '0') {
				isFirstNodeOverflowed = true;
			}
			cnt++;
		}
	}

	return isFirstNodeOverflowed ? Math.max(0, cnt - 1) : cnt;
};
